// METHOD 2: Custom timeout wrapper using Worker Threads (for complex cases)
const { Worker } = require('worker_threads');
const path = require('path');

function testRegexWithTimeout(pattern, input, timeout = 1000) {
  return new Promise((resolve, reject) => {
    const worker = new Worker(path.join(__dirname, 'regex-worker.js'), {
      workerData: { pattern: pattern.toString(), input }
    });

    const timer = setTimeout(() => {
      worker.terminate();
      reject(new Error('Regex execution timeout'));
    }, timeout);

    worker.on('message', (result) => {
      clearTimeout(timer);
      resolve(result);
    });

    worker.on('error', (error) => {
      clearTimeout(timer);
      reject(error);
    });
  });
}

